{
  "meta": {
    "planId": "plan-ecommerce-aks-001",
    "generatedAt": "2026-03-10T21:44:36.398Z",
    "version": "0.1-draft",
    "status": "draft"
  },
  "inputs": {
    "userGoal": "Migrate e-commerce platform with 5 microservices (product catalog, order management, user authentication, payment processing, notifications) to Azure. Deploy on AKS with proper networking, monitoring, and a managed database."
  },
  "plan": {
    "architecturePrinciples": [
      "Highly available with zone redundancy",
      "Secure by default with private networking and managed identities",
      "Observable with centralized logging and APM",
      "Scalable with AKS autoscaling",
      "Well-Architected Framework aligned"
    ],
    "resources": [
      {
        "name": "vnet-ecommerce-prod-eastus-001",
        "type": "Microsoft.Network/virtualNetworks",
        "location": "eastus",
        "sku": "N/A",
        "properties": {
          "addressSpace": {
            "addressPrefixes": ["10.0.0.0/14"]
          },
          "subnets": [
            {
              "name": "snet-aks-system",
              "addressPrefix": "10.0.0.0/16",
              "purpose": "AKS system and user node pools (Azure CNI ŌĆö needs IPs for nodes + pods)"
            },
            {
              "name": "snet-postgres",
              "addressPrefix": "10.1.0.0/24",
              "delegation": "Microsoft.DBforPostgreSQL/flexibleServers",
              "purpose": "PostgreSQL Flexible Server (dedicated delegated subnet)"
            },
            {
              "name": "snet-privateendpoints",
              "addressPrefix": "10.1.1.0/24",
              "purpose": "Private endpoints for ACR, Key Vault, Redis"
            }
          ]
        },
        "reasoning": {
          "whyChosen": "Hub-less VNet design keeps complexity low while enabling private connectivity for all services via subnets and private endpoints. /14 address space provides ample room for AKS CNI pod IPs and future growth.",
          "alternativesConsidered": ["Hub-spoke topology with Azure Firewall", "No VNet (public endpoints only)"],
          "tradeoffs": "Simpler than hub-spoke but lacks centralized egress filtering. Can add Azure Firewall later if needed."
        },
        "dependencies": [],
        "references": [
          { "title": "VNet overview", "url": "https://learn.microsoft.com/azure/virtual-network/virtual-networks-overview" }
        ]
      },
      {
        "name": "aks-ecommerce-prod-001",
        "type": "Microsoft.ContainerService/managedClusters",
        "location": "eastus",
        "sku": "Base/Standard",
        "properties": {
          "kubernetesVersion": "1.31",
          "dnsPrefix": "aks-ecommerce-prod",
          "identity": "SystemAssigned",
          "networkProfile": {
            "networkPlugin": "azure",
            "networkPolicy": "azure",
            "serviceCidr": "10.2.0.0/16",
            "dnsServiceIP": "10.2.0.10"
          },
          "agentPoolProfiles": [
            {
              "name": "systempool",
              "mode": "System",
              "vmSize": "Standard_DS2_v2",
              "count": 3,
              "enableAutoScaling": true,
              "minCount": 3,
              "maxCount": 5,
              "availabilityZones": ["1", "2", "3"],
              "vnetSubnetID": "snet-aks-system"
            },
            {
              "name": "apppool",
              "mode": "User",
              "vmSize": "Standard_DS3_v2",
              "count": 3,
              "enableAutoScaling": true,
              "minCount": 3,
              "maxCount": 10,
              "availabilityZones": ["1", "2", "3"],
              "vnetSubnetID": "snet-aks-system"
            }
          ],
          "addonProfiles": {
            "omsagent": { "enabled": true, "logAnalyticsWorkspaceResourceID": "log-ecommerce-prod-001" },
            "azureKeyvaultSecretsProvider": { "enabled": true }
          }
        },
        "reasoning": {
          "whyChosen": "AKS Standard tier provides 99.95% SLA with availability zones ŌĆö ideal for production e-commerce. Azure CNI gives pods direct VNet IPs for seamless access to PostgreSQL and Redis. Two node pools separate system workloads from application microservices.",
          "alternativesConsidered": ["Azure Container Apps", "AKS Automatic", "App Service"],
          "tradeoffs": "AKS provides maximum control over Kubernetes but requires more operational overhead than Container Apps. Justified by 5 microservices needing fine-grained networking and scaling."
        },
        "dependencies": ["vnet-ecommerce-prod-eastus-001", "log-ecommerce-prod-001"],
        "dependencyReasoning": "AKS nodes deploy into the VNet subnet. Container Insights addon requires a Log Analytics workspace.",
        "references": [
          { "title": "AKS overview", "url": "https://learn.microsoft.com/azure/aks/intro-kubernetes" },
          { "title": "AKS networking concepts", "url": "https://learn.microsoft.com/azure/aks/concepts-network" },
          { "title": "Bicep reference (2025-05-01)", "url": "https://learn.microsoft.com/azure/templates/microsoft.containerservice/managedclusters?pivots=deployment-language-bicep" }
        ]
      },
      {
        "name": "crecommerceprod001",
        "type": "Microsoft.ContainerRegistry/registries",
        "location": "eastus",
        "sku": "Premium",
        "properties": {
          "adminUserEnabled": false,
          "publicNetworkAccess": "Disabled",
          "zoneRedundancy": "Enabled",
          "networkRuleBypassOptions": "AzureServices"
        },
        "reasoning": {
          "whyChosen": "Premium SKU required for private endpoint support, zone redundancy, and geo-replication capability. Admin user disabled in favor of managed identity (acrPull role for AKS).",
          "alternativesConsidered": ["Standard SKU with public access", "Docker Hub"],
          "tradeoffs": "Premium costs more than Standard but enables private networking and zone redundancy critical for production e-commerce."
        },
        "dependencies": ["vnet-ecommerce-prod-eastus-001", "aks-ecommerce-prod-001"],
        "dependencyReasoning": "ACR uses a private endpoint in the VNet. AKS cluster identity needs acrPull role assignment on this registry.",
        "references": [
          { "title": "Container Registry overview", "url": "https://learn.microsoft.com/azure/container-registry/container-registry-intro" },
          { "title": "ACR SKU tiers", "url": "https://learn.microsoft.com/azure/container-registry/container-registry-skus" }
        ]
      },
      {
        "name": "psql-ecommerce-prod-001",
        "type": "Microsoft.DBforPostgreSQL/flexibleServers",
        "location": "eastus",
        "sku": "Standard_D4s_v3 / GeneralPurpose",
        "properties": {
          "version": "16",
          "administratorLogin": "pgadmin",
          "storage": {
            "storageSizeGB": 128,
            "autoGrow": "Enabled"
          },
          "backup": {
            "backupRetentionDays": 14,
            "geoRedundantBackup": "Disabled"
          },
          "highAvailability": {
            "mode": "ZoneRedundant"
          },
          "network": {
            "delegatedSubnetResourceId": "snet-postgres",
            "privateDnsZoneArmResourceId": "privatelink.postgres.database.azure.com"
          },
          "authConfig": {
            "activeDirectoryAuth": "Enabled",
            "passwordAuth": "Enabled"
          }
        },
        "reasoning": {
          "whyChosen": "PostgreSQL Flexible Server with GeneralPurpose tier (4 vCores, 16 GiB RAM) handles e-commerce transactional workloads well. Zone-redundant HA ensures database availability during zone failures. VNet integration via delegated subnet provides private-only access.",
          "alternativesConsidered": ["Azure SQL Database", "Cosmos DB", "Burstable tier PostgreSQL"],
          "tradeoffs": "GeneralPurpose tier costs more than Burstable but provides consistent performance under load. PostgreSQL chosen over Azure SQL for open-source flexibility. Cosmos DB would add latency complexity for transactional patterns."
        },
        "dependencies": ["vnet-ecommerce-prod-eastus-001"],
        "dependencyReasoning": "PostgreSQL uses a delegated subnet in the VNet and a private DNS zone for name resolution.",
        "references": [
          { "title": "PostgreSQL Flexible Server overview", "url": "https://learn.microsoft.com/azure/postgresql/flexible-server/overview" },
          { "title": "Compute and storage options", "url": "https://learn.microsoft.com/azure/postgresql/flexible-server/concepts-compute-storage" }
        ]
      },
      {
        "name": "redis-ecommerce-prod-001",
        "type": "Microsoft.Cache/redis",
        "location": "eastus",
        "sku": "Standard/C2",
        "properties": {
          "sku": {
            "name": "Standard",
            "family": "C",
            "capacity": 2
          },
          "enableNonSslPort": false,
          "minimumTlsVersion": "1.2",
          "publicNetworkAccess": "Disabled",
          "redisConfiguration": {
            "maxmemory-policy": "allkeys-lru"
          }
        },
        "reasoning": {
          "whyChosen": "Standard C2 (2.5 GB) provides SLA-backed caching with replication for session state, product catalog caching, and rate limiting. allkeys-lru eviction policy suits caching patterns. Private endpoint secures access.",
          "alternativesConsidered": ["Premium tier with VNet injection", "In-cluster Redis (Helm chart)", "Basic tier"],
